template.minimal:
-- WIDTH_BUCKET: equal value range
SELECT width_bucket(revenue, 0, 1000, 10) AS revenue_bucket FROM sales;
-- NTILE: equal count
SELECT ntile(4) OVER (ORDER BY revenue) AS quartile FROM sales;

mistake_patterns.good_sql:
SELECT width_bucket(COALESCE(revenue, 0), 0, 1000, 5) AS rev_bucket FROM sales;
-- Or filter NULLs first:
SELECT width_bucket(revenue, 0, 1000, 5) AS rev_bucket FROM sales WHERE revenue IS NOT NULL;

SELECT width_bucket(revenue, (SELECT MIN(revenue) FROM sales), (SELECT MAX(revenue) FROM sales), 5) FROM sales;
-- Or cap outliers:
SELECT width_bucket(LEAST(GREATEST(revenue, 0), 1000), 0, 1000, 5) FROM sales;

mistake_patterns.detection_sql:
-- Run the query twice — if percentiles differ, caching is missing
SELECT PERCENTILE_CONT(0.25) WITHIN GROUP (ORDER BY revenue) FROM sales;
SELECT PERCENTILE_CONT(0.75) WITHIN GROUP (ORDER BY revenue) FROM sales;

mistake_patterns.good_sql:
SELECT
  50 + 20 * GREATEST(-3, LEAST(3, (value - mean) / NULLIF(stddev, 0)))
  FROM stats;
